    }

    fun processRaceEndUpdates() {
        val toJail = mutableListOf<Pilot>()
        val fromJail = mutableListOf<Pilot>()

        hiredPilots.toList().forEach { pilot ->
            if (pilot.hasFine()) {
                pilot.setFineDeadline(pilot.getFineDeadline() - 1)
                if (pilot.getFineDeadline() <= 0) {
                    toJail.add(pilot)
