package com.bmstu.iu3.automanagement.data
/** * Data classes для сериализации состояния игры */
// Сохраняемые данные компонента data class ComponentSaveData( val id: String, val name: String, val price: Double, val performance: Double, val wear: Double, val isDestroyed: Boolean, val type: String, // Engine, Gearbox, Chassis, etc. // Специфичные для типа поля val power: Int?, val weight: Int?, val gears: Int? )
// Сохраняемые данные машины data class CarSaveData( val name: String, val performance: Double, val engine: ComponentSaveData?, val gearbox: ComponentSaveData?, val chassis: ComponentSaveData?, val suspension: ComponentSaveData?, val aerodynamics: ComponentSaveData?, val tyres: ComponentSaveData? )
// Сохраняемые данные работника (инженер/пилот) data class WorkerSaveData( val name: String, val skill: Int, val salary: Double, val type: String, // Engineer or Pilot // Специфичные для пилота поля val fineAmount: Double?, val fineDeadline: Int?, val jailSentence: Int? )
// Сохраняемые данные результата гонки data class RaceResultSaveData( val pilotName: String, val position: Int, val time: Double, val incidents: String // сериализованный список инцидентов )
// Главный класс сохранённого состояния data class GameStateSaveData( val playerName: String, val budget: Double, val ownedComponents: List<ComponentSaveData>, val assembledCars: List<CarSaveData>, val hiredEngineers: List<WorkerSaveData>, val hiredPilots: List<WorkerSaveData>, val jailedPilots: List<WorkerSaveData>, val raceHistory: List<List<RaceResultSaveData>>, val timestamp: Long )

package com.bmstu.iu3.automanagement.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.NavHostController
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import com.bmstu.iu3.automanagement.ui.screens.*

@Composable
fun SetupNavGraph(navController: NavHostController, onExit: () -> Unit) {
    NavHost(
        navController = navController,
        startDestination = Screen.MainMenu.route
    ) {
        composable(Screen.MainMenu.route) {
            MainMenuScreen(
                onNavigate = { route -> navController.navigate(route) },
                onExit = onExit
            )
        }
        composable(Screen.StartRace.route) {
            StartRaceScreen(
                onBack = { navController.popBackStack() },
                onRaceComplete = {
                    navController.navigate(Screen.ViewResults.route) {
                        popUpTo(Screen.MainMenu.route)
                    }
                }
            )
        }
        composable(Screen.BuyComponents.route) {
            BuyComponentsScreen { navController.popBackStack() }
        }
        composable(Screen.Garage.route) {
            AssembleCarScreen { navController.popBackStack() }
        }
        composable(Screen.HireEngineers.route) {
            HireEngineersScreen { navController.popBackStack() }
        }
        composable(Screen.HirePilots.route) {
            HirePilotsScreen { navController.popBackStack() }
        }
        composable(Screen.ViewCars.route) {
            ViewCarsScreen { navController.popBackStack() }
        }
        composable(Screen.ViewPersonnel.route) {
            ViewPersonnelScreen { navController.popBackStack() }
        }
        composable(Screen.ViewStats.route) {
            ViewStatsScreen { navController.popBackStack() }
        }
        composable(Screen.ViewTeams.route) {
            ViewTeamsScreen { navController.popBackStack() }
        }
        composable(Screen.ViewResults.route) {
            ViewResultsScreen { navController.popBackStack() }
        }
    }
}

package com.bmstu.iu3.automanagement.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.NavHostController
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import com.bmstu.iu3.automanagement.data.GameState
import com.bmstu.iu3.automanagement.data.GameSaveManager
import com.bmstu.iu3.automanagement.ui.screens.*

@Composable
fun SetupNavGraph(
    navController: NavHostController,
    onExit: () -> Unit,
    saveManager: GameSaveManager
) {
    NavHost(
        navController = navController,
        startDestination = Screen.PlayerSelection.route
    ) {
        composable(Screen.PlayerSelection.route) {
            PlayerSelectionScreen(
                saveManager = saveManager,
                onPlayerSelected = {
                    navController.navigate(Screen.MainMenu.route) {
                        popUpTo(Screen.PlayerSelection.route) { inclusive = true }
                    }
                }
            )
        }
        composable(Screen.MainMenu.route) {
            MainMenuScreen(
                onNavigate = { route -> navController.navigate(route) },
                onExit = {
                    saveManager.saveGame(GameState.getCurrentPlayer())
                    onExit()
                }
            )
        }
        composable(Screen.StartRace.route) {
            StartRaceScreen(
                onBack = { navController.popBackStack() },
                onRaceComplete = {
                    saveManager.saveGame(GameState.getCurrentPlayer())
                    navController.navigate(Screen.ViewResults.route) {
                        popUpTo(Screen.MainMenu.route)
                    }
                }
            )
        }
        composable(Screen.BuyComponents.route) {
            BuyComponentsScreen {
                saveManager.saveGame(GameState.getCurrentPlayer())
                navController.popBackStack()
            }
        }
        composable(Screen.Garage.route) {
            AssembleCarScreen {
                saveManager.saveGame(GameState.getCurrentPlayer())
                navController.popBackStack()
            }
        }
        composable(Screen.HireEngineers.route) {
            HireEngineersScreen {
                saveManager.saveGame(GameState.getCurrentPlayer())
                navController.popBackStack()
            }
        }
        composable(Screen.HirePilots.route) {
            HirePilotsScreen {
                saveManager.saveGame(GameState.getCurrentPlayer())
                navController.popBackStack()
            }
        }
        composable(Screen.ViewCars.route) {
            ViewCarsScreen { navController.popBackStack() }
        }
        composable(Screen.ViewPersonnel.route) {
            ViewPersonnelScreen { navController.popBackStack() }
        }
        composable(Screen.ViewStats.route) {
            ViewStatsScreen { navController.popBackStack() }
        }
        composable(Screen.ViewTeams.route) {
            ViewTeamsScreen { navController.popBackStack() }
        }
        composable(Screen.ViewResults.route) {
            ViewResultsScreen { navController.popBackStack() }
        }
    }
}

package com.bmstu.iu3.automanagement.ui.screens

import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material.icons.Icons
import androidx.compose.material.icons.filled.Delete
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.text.font.Font
import androidx.compose.ui.text.font.FontFamily
import androidx.compose.ui.unit.dp
import com.bmstu.iu3.automanagement.R.font.press_start2p
import com.bmstu.iu3.automanagement.data.PlayerProfileManager
import com.bmstu.iu3.automanagement.ui.theme.PixelButton

@Composable
fun PlayerSelectionScreen(
    profileManager: PlayerProfileManager,
    onPlayerSelected: () -> Unit
) {
    var playerName by remember { mutableStateOf("") }
    var existingPlayers by remember { mutableStateOf(profileManager.getAllPlayerNames().toList()) }
    var showCreateDialog by remember { mutableStateOf(false) }
    var selectedPlayer by remember { mutableStateOf<String?>(null) }

    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(16.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
        verticalArrangement = Arrangement.Top
    ) {
        Text(
            text = "Select Player",
            style = MaterialTheme.typography.headlineMedium,
            fontFamily = FontFamily(Font(press_start2p)),
            modifier = Modifier.padding(top = 16.dp, bottom = 24.dp)
        )

        if (existingPlayers.isEmpty()) {
            Text(
                text = "No players found",
                style = MaterialTheme.typography.bodyLarge,
                modifier = Modifier.padding(bottom = 24.dp)
            )
        } else {
            LazyColumn(
                modifier = Modifier
                    .fillMaxWidth()
                    .weight(1f),
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                items(existingPlayers) { player ->
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = 8.dp),
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        PixelButton(
                            text = player,
                            onClick = {
                                selectedPlayer = player
                                if (profileManager.loadProfile(player)) {
                                    onPlayerSelected()
                                }
                            },
                            modifier = Modifier.weight(1f),
                            baseColor = if (selectedPlayer == player)
                                MaterialTheme.colorScheme.primary
                            else
                                MaterialTheme.colorScheme.secondary
                        )
                        IconButton(
                            onClick = {
                                profileManager.deleteProfile(player)
                                existingPlayers = profileManager.getAllPlayerNames().toList()
                                if (selectedPlayer == player) selectedPlayer = null
                            }
                        ) {
                            Icon(
                                Icons.Default.Delete,
                                contentDescription = "Delete player",
                                tint = MaterialTheme.colorScheme.error
                            )
                        }
                    }
                }
            }
        }

        Spacer(modifier = Modifier.height(16.dp))

        PixelButton(
            text = "New Player",
            onClick = { showCreateDialog = true },
            modifier = Modifier.fillMaxWidth(),
            baseColor = MaterialTheme.colorScheme.primary
        )
    }

    if (showCreateDialog) {
        NewPlayerDialog(
            onDismiss = { showCreateDialog = false },
            onCreatePlayer = { name ->
                if (name.isNotEmpty()) {
                    if (profileManager.createOrLoadProfile(name)) {
                        existingPlayers = profileManager.getAllPlayerNames().toList()
                        showCreateDialog = false
                        onPlayerSelected()
                    }
                }
            }
        )
    }
}

@Composable
fun NewPlayerDialog(
    onDismiss: () -> Unit,
    onCreatePlayer: (String) -> Unit
) {
    var playerName by remember { mutableStateOf("") }
    var errorMessage by remember { mutableStateOf("") }

    AlertDialog(
        onDismissRequest = onDismiss,
        title = { Text("Enter Player Name") },
        text = {
            Column {
                OutlinedTextField(
                    value = playerName,
                    onValueChange = {
                        playerName = it
                        errorMessage = ""
                    },
                    label = { Text("Player Name") },
                    modifier = Modifier.fillMaxWidth(),
                    singleLine = true
                )
                if (errorMessage.isNotEmpty()) {
                    Text(
                        text = errorMessage,
                        color = MaterialTheme.colorScheme.error,
                        style = MaterialTheme.typography.bodySmall,
                        modifier = Modifier.padding(top = 8.dp)
                    )
                }
            }
        },
        confirmButton = {
            Button(
                onClick = {
                    when {
                        playerName.isEmpty() -> errorMessage = "Name cannot be empty"
                        playerName.length > 20 -> errorMessage = "Name is too long (max 20 characters)"
                        else -> onCreatePlayer(playerName)
                    }
                }
            ) {
                Text("Create")
            }
        },
        dismissButton = {
            Button(onClick = onDismiss) {
                Text("Cancel")
            }
        }
    )
}

